        slide_2 = list(prs.slides)[1]

        # Search for 'File System' text in all text-containing shapes
        file_system_found = False

        for shape in slide_2.shapes:
            if hasattr(shape, 'text_frame') and shape.text_frame:
                full_text = shape.text_frame.text.lower()
                if 'file system' in full_text:
                    file_system_found = True
                    break
            elif hasattr(shape, 'text'):
                if 'file system' in shape.text.lower():
                    file_system_found = True
                    break

        if file_system_found:
            return "'File System' bullet point found on slide 2", 1.0
        else:
            return "'File System' bullet point not found on slide 2", 0.0

    except Exception as e:
        return f"Error checking for File System bullet point: {str(e)}", 0.0

def compute_score() -> tuple[str, float]:
    from pptx import Presentation

    try:
        prs = Presentation(modified_ppt_path)
        slide_2 = list(prs.slides)[1]

        # Find text frames that contain both 'Dual Mode' and 'File System'
        for shape in slide_2.shapes:
            if hasattr(shape, 'text_frame') and shape.text_frame:
                full_text = shape.text_frame.text.lower()

                # Check if both terms exist in this text frame
                if 'dual mode' in full_text and 'file system' in full_text:
                    # Find positions of both terms
                    dual_mode_pos = full_text.find('dual mode')
                    file_system_pos = full_text.find('file system')

                    if file_system_pos > dual_mode_pos:
                        return "'File System' correctly positioned after 'Dual Mode'", 1.0
                    else:
                        return "'File System' found but not positioned after 'Dual Mode'", 0.0

        return "Could not find both 'Dual Mode' and 'File System' in the same text context", 0.0

    except Exception as e:
        return f"Error checking positioning: {str(e)}", 0.0

def compute_score() -> tuple[str, float]:
    # Check if any slides were added or removed
    if ppt_diff.added_slides:
        return f"Unwanted slides added: {len(ppt_diff.added_slides)} slides", 0.0

    if ppt_diff.removed_slides:
        return f"Slides were removed: {len(ppt_diff.removed_slides)} slides", 0.0

    # Check for modifications to slides other than slide 2
    problematic_modifications = []
    for old_slide, new_slide in ppt_diff.modified_slides:
        if new_slide.slide_number != 2:
            # Only flag if there are significant changes (not just element count changes)
            if (old_slide.title != new_slide.title or 
                old_slide.layout_type != new_slide.layout_type):
                problematic_modifications.append(new_slide.slide_number)

    if problematic_modifications:
        return f"Unwanted modifications to slides: {problematic_modifications}", 0.5

    return "No unwanted slide structure changes detected", 1.0

def compute_score() -> tuple[str, float]:
    issues = []

    if ppt_diff.added_animations:
        issues.append(f"Added {len(ppt_diff.added_animations)} animations")

    if ppt_diff.removed_animations:
        issues.append(f"Removed {len(ppt_diff.removed_animations)} animations")

    if ppt_diff.modified_animations:
        issues.append(f"Modified {len(ppt_diff.modified_animations)} animations")

    if ppt_diff.added_transitions:
        issues.append(f"Added {len(ppt_diff.added_transitions)} transitions")

    if ppt_diff.removed_transitions:
        issues.append(f"Removed {len(ppt_diff.removed_transitions)} transitions")

    if ppt_diff.modified_transitions:
        issues.append(f"Modified {len(ppt_diff.modified_transitions)} transitions")

    if issues:
        return f"Unwanted animation/transition changes: {'; '.join(issues)}", 0.0

    return "No unwanted animation or transition changes", 1.0
